### Launch Document Scanner with React Native

Source: https://context7.com/dariyd/react-native-document-scanner/llms.txt

Launches the native document scanner interface, allowing users to capture and process documents. It returns a promise resolving with scan results, including image URIs, metadata, and optional base64 data. Handles camera permissions automatically. Supports configuration for quality and base64 encoding.

```javascript
import { launchScanner } from '@dariyd/react-native-document-scanner';
import { Alert, Image } from 'react-native';

// Basic usage with default settings (quality: 1.0, no base64)
const scanDocument = async () => {
  try {
    const result = await launchScanner();

    if (result.didCancel) {
      console.log('User cancelled the scan');
      return;
    }

    if (result.error) {
      Alert.alert('Error', result.errorMessage || 'Scan failed');
      return;
    }

    if (result.images && result.images.length > 0) {
      result.images.forEach((image, index) => {
        console.log(`Page ${index + 1}:`);
        console.log(`  URI: ${image.uri}`);
        console.log(`  Size: ${image.width}x${image.height}`);
        console.log(`  File: ${image.fileName} (${image.fileSize} bytes)`);
        console.log(`  Type: ${image.type}`);
      });

      // Display first scanned page
      return <Image source={{ uri: result.images[0].uri }} style={{ width: 300, height: 400 }} />;
    }
  } catch (error) {
    console.error('Scan error:', error);
    Alert.alert('Error', 'Failed to launch scanner');
  }
};

// Advanced usage with quality compression and base64 encoding
const scanWithOptions = async () => {
  const result = await launchScanner({
    quality: 0.8,           // 80% JPEG quality (reduces file size)
    includeBase64: true     // Include base64 string in result
  });

  if (result.images && result.images.length > 0) {
    const firstImage = result.images[0];

    // Upload to server using base64
    const uploadData = {
      imageData: firstImage.base64,
      fileName: firstImage.fileName,
      width: firstImage.width,
      height: firstImage.height,
      mimeType: firstImage.type
    };

    await fetch('https://api.example.com/upload', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(uploadData)
    });
  }
};

// Callback-based usage (alternative to promises)
launchScanner({ quality: 0.9 }, (result) => {
  if (result.didCancel) {
    console.log('User cancelled');
  } else if (result.error) {
    console.log('Error:', result.errorMessage);
  } else if (result.images) {
    console.log(`Scanned ${result.images.length} pages`);
  }
});
```

